use std::collections::HashMap;

struct JobConfig {
    job_name: String,
    command: String,
    dependencies: Vec<String>,
}

fn parse_job_string(input: &str) -> Result<JobConfig, &'static str> {
    let parts: Vec<&str> = input.splitn(3, ':').collect();
    if parts.len() != 3 {
        return Err("Invalid format: expected name:command:deps");
    }

    let job_name = parts[0].trim().to_string();
    let command = parts[1].trim().to_string();

    let mut dependencies = Vec::new();
    if !parts[2].is_empty() {
        dependencies = parts[2]
            .split(',')
            .map(|s| s.trim().to_string()) 
            .collect();
    }

    Ok(JobConfig {
        job_name,
        command,
        dependencies,
    })
}

fn main() {
    let job_data = "build_service:cargo run --release:backend,api";
    match parse_job_string(job_data) {
        Ok(config) => {
            println!("Successfully parsed job for {}", config.job_name);
            println!("Command: {}", config.command);
            println!("Dependencies: {:?}", config.dependencies);
        }
        Err(e) => {
            eprintln!("Error parsing data: {}", e);
        }
    }
}

use std::collections::HashMap;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let reader = BufReader::new(io::stdin());
    let mut cache_map: HashMap<String, String> = HashMap::new();

    for line in reader.lines() {
        let line = line?;
        if let Some((key, value)) = line.split_once(':') {
            let key_owned = key.to_string();
            let value_owned = value.to_string();
            cache_map.insert(key_owned, value_owned);
        }
    }

    println!("Successfully parsed {} entries into the cache map.", cache_map.len());
    if let Some(value) = cache_map.get("test_key") {
        println!("Value for 'test_key': {}", value);
    }

    Ok(())
}

use std::collections::HashMap;

struct ItemData {
    name: String,
    power_level: u32,
    craft_cost: i32,
}

fn parse_item_string(input: &str) -> Option<ItemData> {
    let parts: Vec<&str> = input.split("|").collect();

    if parts.len() < 3 {
        return None;
    }

    let name = parts[0].trim().to_string();

    let power_result = parts[1].trim().parse::<u32>();
    if !power_result.is_ok() {
        return None;
    }
    let power_level = power_result.unwrap();

    let cost_result = parts[2].trim().parse::<i32>();
    if !cost_result.is_ok() {
        return None;
    }
    let craft_cost = cost_result.unwrap();

    Some(ItemData {
        name,
        power_level,
        craft_cost,
    })
}

fn main() {
    let item_string = "Sword|150|25";
    match parse_item_string(item_string) {
        Some(data) => {
            println!("Successfully parsed item: {}", data.name);
            println!("Power Level: {}", data.power_level);
            println!("Cost: {}", data.craft_cost);
        }
        None => {
            eprintln!("Failed to parse item string.");
        }
    }

    let bad_string = "Shield|abc|10";
    match parse_item_string(bad_string) {
        Some(_) => {}
        None => println!("Correctly rejected malformed input.")
    }
}

use std::collections::HashMap;

#[derive(Debug)]
struct RegisterBlock {
    base_address: u32,
    size_bytes: usize,
}

fn parse_packet_payload(raw_data: &[u8]) -> Result<HashMap<u32, u32>, String> {
    let mut results = HashMap::new();
    if raw_data.len() < 4 {
        return Err("Incomplete packet header".to_string());
    }

    let num_blocks = u32::from_le_bytes(raw_data[0..4].try_into().unwrap());
    let mut offset = 4;

    for _ in 0..num_blocks {
        if offset >= raw_data.len() {
            return Err("Unexpected end of packet data while reading block count".to_string());
        }

        let block_size = u32::from_le_bytes(raw_data[offset..offset+4].try_into().unwrap()) as usize;
        if offset + 4 + block_size > raw_data.len() {
            return Err("Declared block size exceeds remaining packet data".to_string());
        }

        let base_addr = u32::from_le_bytes(raw_data[offset+4..offset+8].try_into().unwrap());
        let start_index = offset + 8;
        let end_index = start_index + block_size;

        for i in (start_index..end_index).step_by(4) {
            if i + 3 >= raw_data.len() {
                break;
            }
            let value = u32::from_le_bytes(raw_data[i..i+4].try_into().unwrap());
            results.insert(base_addr + (i - start_index) as u32, value);
        }

        offset += 4 + block_size;
    }

    Ok(results)
}

fn main() {
    let mock_packet: [u8; 32] = [0x01, 0x00, 0x00, 0x00, 0x03, 0x00, 0x00, 0x00, 0x0A, 0x00, 0x00, 0x00, 
                                 0x05, 0x00, 0x00, 0x00, 0x10, 0x00, 0x00, 0x00, 0xAA, 0xBB, 0xCC, 0xDD, 
                                 0x12, 0x34, 0x56, 0x78, 0x90, 0xAB, 0xCD, 0xEF];
    match parse_packet_payload(&mock_packet) {
        Ok(map) => println!("Successfully parsed {} registers.", map.len()),
        Err(e) => println!("Parsing error: {}", e),
    }
}

use std::collections::HashMap;

struct ScoreboardEvent {
    timestamp: String,
    home_score: u32,
    away_score: u32,
}

fn parse_scoreboard_line(line: &str) -> Option<ScoreboardEvent> {
    let parts: Vec<&str> = line.split("|").collect();
    if parts.len() < 3 {
        return None;
    }

    let timestamp = parts[0].to_string();
    let home_score_str = parts[1];
    let away_score_str = parts[2];

    match (home_score_str.parse::<u32>(), away_score_str.parse::<u32>()) {
        (Ok(h), Ok(a)) => Some(ScoreboardEvent {
            timestamp,
            home_score: h,
            away_score: a,
        }),
        _ => None,
    }
}

fn process_event_stream(input_data: &str) -> HashMap<String, u32> {
    let mut last_score: HashMap<String, u32> = HashMap::new();

    for line in input_data.lines() {
        if let Some(event) = parse_scoreboard_line(line) {
            let key = format!("{}:{}", &event.timestamp, "Final");
            last_score.insert(key, event.home_score.saturating_add(event.away_score));
        }
    }
    last_score
}
